import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: {(project_basename, framework, package_id): version}
def build_lookup(data):
    lookup = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                lookup[(name, fw['framework'], pkg['id'])] = pkg['resolvedVersion']
    return lookup

b = build_lookup(baseline)
a = build_lookup(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))

print('=== CHANGES ===')
changes = False
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv != av:
        changes = True
        proj, fw, pkg = k
        if bv and av:
            print(f'  {proj} ({fw}): {pkg} {bv} -> {av}')
        elif bv:
            print(f'  {proj} ({fw}): {pkg} {bv} -> REMOVED')
        else:
            print(f'  {proj} ({fw}): {pkg} ADDED as {av}')

if not changes:
    print('  None')

print()
print('=== UNCHANGED ===')
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv == av:
        proj, fw, pkg = k
        print(f'  {proj} ({fw}): {pkg} {bv}')
"

